def random_in_range(low, high):
    range = high - low
    return low + math_random() * range

def estimate_integral(pred, x1, x2, y1, y2, trials):
    area_rect = (x2 - x1) * (y2 - y1)
    return monte_carlo(trials,
                       lambda: pred(random_in_range(x1, x2),
                                    random_in_range(y1, y2))) * area_rect

state = 2

def rand(symbol):
    global state
    if symbol == "reset":
        def reset(new_state):
            global state
            state = new_state
        return reset
    else:
        # symbol is "generate"
        state = (state * 1010) % 1101
        return state
